class Animal {
public:
    // Virtual allows derived classes to override this behavior at runtime
    virtual void speak() { std::cout << "Generic sound\n"; }
    virtual ~Animal() = default; // ALWAYS make base destructors virtual!
};

class Dog : public Animal {
public:
    void speak() override { std::cout << "Bark!\n"; }
};

int main() {
    Animal* myPet = new Dog(); // Base pointer to derived object
    myPet->speak(); // Outputs "Bark!" due to dynamic dispatch
    delete myPet;
}

