#include <vector>
#include <algorithm>

std::vector<int> nums = {5, 2, 8, 1, 9};
int threshold = 4;

// [threshold] captures the variable by value from the surrounding scope
auto it = std::find_if(nums.begin(), nums.end(), [threshold](int n) {
    return n > threshold;
});
std::cout << "First number > 4 is: " << *it << "\n";

#include <thread>
#include <mutex>

int sharedCounter = 0;
std::mutex mtx;

void increment() {
    for (int i = 0; i < 10000; i++) {
        std::lock_guard<std::mutex> lock(mtx); // Locks mutex, unlocks automatically at scope end
        sharedCounter++; // Safely modifies shared memory
    }
}

int main() {
    std::thread t1(increment);
    std::thread t2(increment);
    t1.join(); // Main thread waits for t1 to finish
    t2.join(); // Main thread waits for t2 to finish
}

// Compile-time Factorial calculation using recursive template instantiation
template<unsigned int n>
struct Factorial {
    enum { value = n * Factorial<n - 1>::value };
};

// Base case specialization to stop the recursion
template<>
struct Factorial<0> {
    enum { value = 1 };
};

int main() {
    // The compiler calculates 5! during compilation.
    // The compiled binary literally just contains: int x = 120;
    int x = Factorial<5>::value; 
}

