// No mutex required. The hardware guarantees this integer cannot be corrupted.
std::atomic<int> atomicCounter(0);

void increment() {
    for (int i = 0; i < 100000; i++) {
        // Translates to a lock-free CPU assembly instruction (e.g., LOCK XADD)
        atomicCounter.fetch_add(1, std::memory_order_relaxed); 
    }
}

